143: #define ALL_LISTENER_MANAGER_STATS(COUNTER, GAUGE)                                                 \
144:   COUNTER(listener_added)                                                                          \
145:   COUNTER(listener_create_failure)                                                                 \
146:   COUNTER(listener_create_success)                                                                 \
147:   COUNTER(listener_in_place_updated)                                                               \
148:   COUNTER(listener_modified)                                                                       \
