150:   COUNTER(listener_stopped)                                                                        \
151:   GAUGE(total_filter_chains_draining, NeverImport)                                                 \
152:   GAUGE(total_listeners_active, NeverImport)                                                       \
153:   GAUGE(total_listeners_draining, NeverImport)                                                     \
154:   GAUGE(total_listeners_warming, NeverImport)                                                      \
155:   GAUGE(workers_started, NeverImport)
