75: absl::StatusOr<std::unique_ptr<ListenSocketFactoryImpl>> ListenSocketFactoryImpl::create(
76:     ListenerComponentFactory& factory, Network::Address::InstanceConstSharedPtr address,
77:     Network::Socket::Type socket_type, const Network::Socket::OptionsSharedPtr& options,
78:     const std::string& listener_name, uint32_t tcp_backlog_size,
79:     ListenerComponentFactory::BindType bind_type,
80:     const Network::SocketCreationOptions& creation_options, uint32_t num_sockets) {
81:   absl::Status creation_status = absl::OkStatus();
82:   auto ret = std::unique_ptr<ListenSocketFactoryImpl>(new ListenSocketFactoryImpl(
83:       factory, address, socket_type, options, listener_name, tcp_backlog_size, bind_type,
84:       creation_options, num_sockets, creation_status));
