197: Network::SocketSharedPtr ListenSocketFactoryImpl::getListenSocket(uint32_t worker_index) {
198:   // Per the TODO above, sockets at this point can never be null. That only happens in the
199:   // config validation path.
200:   ASSERT(worker_index < sockets_.size() && sockets_[worker_index] != nullptr);
201:   return sockets_[worker_index];
202: }
