204: absl::Status ListenSocketFactoryImpl::doFinalPreWorkerInit() {
205:   if (bind_type_ == ListenerComponentFactory::BindType::NoBind ||
206:       socket_type_ != Network::Socket::Type::Stream) {
207:     return absl::OkStatus();
208:   }
209: 
210:   ASSERT(!sockets_.empty());
211:   auto listen_and_apply_options = [](Envoy::Network::SocketSharedPtr socket, int tcp_backlog_size) {
212:     const auto rc = socket->ioHandle().listen(tcp_backlog_size);
213:     if (rc.return_value_ != 0) {
214:       return absl::InvalidArgumentError(fmt::format("cannot listen() errno={}", rc.errno_));
215:     }
216:     if (!Network::Socket::applyOptions(socket->options(), *socket,
217:                                        envoy::config::core::v3::SocketOption::STATE_LISTENING)) {
218:       std::string message =
219:           fmt::format("cannot set post-listen socket option on socket: {}",
220:                       socket->connectionInfoProvider().localAddress()->asString());
221:       return absl::InvalidArgumentError(message);
222:     }
223:     return absl::OkStatus();
224:   };
225:   // On all platforms we should listen on the first socket.
226:   auto iterator = sockets_.begin();
227:   RETURN_IF_NOT_OK(listen_and_apply_options(*iterator, tcp_backlog_size_));
228:   ++iterator;
229: #ifndef WIN32
230:   // With this implementation on Windows we only accept
231:   // connections on Worker 1 and then we use the `ExactConnectionBalancer`
232:   // to balance these connections to all workers.
233:   // TODO(davinci26): We should update the behavior when socket duplication
234:   // does not cause accepts to hang in the OS.
235:   for (; iterator != sockets_.end(); ++iterator) {
236:     RETURN_IF_NOT_OK(listen_and_apply_options(*iterator, tcp_backlog_size_));
237:   }
238: #endif
239:   return absl::OkStatus();
240: }
