348:         std::make_shared<Network::Address::EnvoyInternalInstance>(config.name()));
349:     address_opts_list.emplace_back(std::ref(config.socket_options()));
350:   } else {
351:     // All the addresses should be same socket type, so get the first address's socket type is
352:     // enough.
353:     auto address_or_error = Network::Address::resolveProtoAddress(config.address());
354:     SET_AND_RETURN_IF_NOT_OK(address_or_error.status(), creation_status);
355:     auto address = std::move(address_or_error.value());
356:     SET_AND_RETURN_IF_NOT_OK(checkIpv4CompatAddress(address, config.address()), creation_status);
357:     addresses_.emplace_back(address);
358:     address_opts_list.emplace_back(std::ref(config.socket_options()));
359: 
360:     for (auto i = 0; i < config.additional_addresses_size(); i++) {
361:       if (socket_type_ !=
362:           Network::Utility::protobufAddressSocketType(config.additional_addresses(i).address())) {
363:         creation_status = absl::InvalidArgumentError(
364:             fmt::format("listener {}: has different socket type. The listener only "
365:                         "support same socket type for all the addresses.",
366:                         name_));
367:         return;
368:       }
369:       auto addresses_or_error =
370:           Network::Address::resolveProtoAddress(config.additional_addresses(i).address());
371:       SET_AND_RETURN_IF_NOT_OK(addresses_or_error.status(), creation_status);
372:       auto additional_address = std::move(addresses_or_error.value());
373:       SET_AND_RETURN_IF_NOT_OK(
374:           checkIpv4CompatAddress(address, config.additional_addresses(i).address()),
375:           creation_status);
376:       addresses_.emplace_back(additional_address);
377:       if (config.additional_addresses(i).has_socket_options()) {
378:         address_opts_list.emplace_back(
379:             std::ref(config.additional_addresses(i).socket_options().socket_options()));
380:       } else {
381:         address_opts_list.emplace_back(std::ref(config.socket_options()));
382:       }
383:     }
384:   }
385: 
386:   const absl::optional<std::string> runtime_val =
387:       listener_factory_context_->serverFactoryContext().runtime().snapshot().get(
388:           cx_limit_runtime_key_);
389:   if (runtime_val && runtime_val->empty()) {
390:     ENVOY_LOG(warn,
391:               "Listener connection limit runtime key {} is empty. There are currently no "
392:               "limitations on the number of accepted connections for listener {}.",
393:               cx_limit_runtime_key_, config.name());
394:   }
395: 
396:   filter_chain_manager_ = std::make_unique<FilterChainManagerImpl>(
397:       addresses_, listener_factory_context_->parentFactoryContext(), initManager()),
398: 
399:   buildAccessLog(config);
400:   SET_AND_RETURN_IF_NOT_OK(validateConfig(), creation_status);
401: 
402:   // buildUdpListenerFactory() must come before buildListenSocketOptions() because the UDP
403:   // listener factory can provide additional options.
404:   SET_AND_RETURN_IF_NOT_OK(buildUdpListenerFactory(config, parent_.server_.options().concurrency()),
405:                            creation_status);
406:   buildListenSocketOptions(config, address_opts_list);
407:   SET_AND_RETURN_IF_NOT_OK(createListenerFilterFactories(config), creation_status);
408:   SET_AND_RETURN_IF_NOT_OK(validateFilterChains(config), creation_status);
409:   SET_AND_RETURN_IF_NOT_OK(buildFilterChains(config), creation_status);
410:   if (socket_type_ != Network::Socket::Type::Datagram) {
411:     buildSocketOptions(config);
412:     buildOriginalDstListenerFilter(config);
413:     buildProxyProtocolListenerFilter(config);
414:     SET_AND_RETURN_IF_NOT_OK(buildInternalListener(config), creation_status);
415:   }
416:   if (!workers_started_) {
417:     // Initialize dynamic_init_manager_ from Server's init manager if it's not initialized.
418:     // NOTE: listener_init_target_ should be added to parent's initManager at the end of the
419:     // listener constructor so that this listener's children entities could register their targets
420:     // with their parent's initManager.
421:     parent_.server_.initManager().add(listener_init_target_);
422:   }
423: }
