535: absl::Status
536: ListenerImpl::buildInternalListener(const envoy::config::listener::v3::Listener& config) {
537:   if (config.has_internal_listener()) {
538:     if (config.has_address() || !config.additional_addresses().empty()) {
539:       return absl::InvalidArgumentError(
540:           fmt::format("error adding listener '{}': address should not be used "
541:                       "when an internal listener config is provided",
542:                       name_));
543:     }
544:     if ((config.has_connection_balance_config() &&
545:          config.connection_balance_config().has_exact_balance()) ||
546:         config.enable_mptcp() ||
547:         config.has_enable_reuse_port() // internal listener doesn't use physical l4 port.
548:         || (config.has_freebind() && config.freebind().value()) || config.has_tcp_backlog_size() ||
549:         config.has_tcp_fast_open_queue_length() ||
550:         (config.has_transparent() && config.transparent().value())) {
551:       return absl::InvalidArgumentError(fmt::format(
552:           "error adding listener named '{}': has unsupported tcp listener feature", name_));
553:     }
554:     if (!config.socket_options().empty()) {
555:       return absl::InvalidArgumentError(
556:           fmt::format("error adding listener named '{}': does not support socket option", name_));
557:     }
558:     std::shared_ptr<Network::InternalListenerRegistry> internal_listener_registry =
559:         parent_.server_.singletonManager().getTyped<Network::InternalListenerRegistry>(
560:             "internal_listener_registry_singleton");
561:     if (internal_listener_registry == nullptr) {
562:       // The internal listener registry may be uninitialized when in Validate mode.
563:       // Hence we check the configuration directly to ensure the bootstrap extension
564:       // InternalListener is present.
565:       if (absl::c_none_of(
566:               listener_factory_context_->serverFactoryContext().bootstrap().bootstrap_extensions(),
567:               [=](const auto& extension) {
568:                 return extension.typed_config().type_url() ==
569:                        "type.googleapis.com/"
570:                        "envoy.extensions.bootstrap.internal_listener.v3.InternalListener";
571:               })) {
572:         return absl::InvalidArgumentError(fmt::format(
573:             "error adding listener named '{}': InternalListener bootstrap extension is mandatory",
574:             name_));
575:       }
576:       internal_listener_config_ = nullptr;
577:     } else {
578:       internal_listener_config_ =
579:           std::make_unique<InternalListenerConfigImpl>(*internal_listener_registry);
580:     }
581:   } else if (config.address().has_envoy_internal_address() ||
582:              std::any_of(config.additional_addresses().begin(), config.additional_addresses().end(),
583:                          [](const envoy::config::listener::v3::AdditionalAddress& proto_address) {
584:                            return proto_address.address().has_envoy_internal_address();
585:                          })) {
586:     return absl::InvalidArgumentError(
587:         fmt::format("error adding listener named '{}': use internal_listener "
588:                     "field instead of address for internal listeners",
589:                     name_));
590:   }
591:   return absl::OkStatus();
592: }
