608: absl::Status
609: ListenerImpl::buildUdpListenerFactory(const envoy::config::listener::v3::Listener& config,
610:                                       uint32_t concurrency) {
611:   if (socket_type_ != Network::Socket::Type::Datagram) {
612:     return absl::OkStatus();
613:   }
614:   if (!reuse_port_ && concurrency > 1) {
615:     return absl::InvalidArgumentError(
616:         "Listening on UDP when concurrency is > 1 without the SO_REUSEPORT "
617:         "socket option results in "
618:         "unstable packet proxying. Configure the reuse_port listener option or "
619:         "set concurrency = 1.");
620:   }
621: 
622:   udp_listener_config_ = std::make_shared<UdpListenerConfigImpl>(config.udp_listener_config());
623:   ProtobufTypes::MessagePtr udp_packet_packet_writer_config;
624:   if (config.udp_listener_config().has_udp_packet_packet_writer_config()) {
625:     auto* factory_factory = Config::Utility::getFactory<Network::UdpPacketWriterFactoryFactory>(
626:         config.udp_listener_config().udp_packet_packet_writer_config());
627:     udp_listener_config_->writer_factory_ = factory_factory->createUdpPacketWriterFactory(
628:         config.udp_listener_config().udp_packet_packet_writer_config());
629:   }
630:   if (config.udp_listener_config().has_quic_options()) {
631: #ifdef ENVOY_ENABLE_QUIC
632:     if (config.has_connection_balance_config()) {
633:       return absl::InvalidArgumentError(
634:           "connection_balance_config is configured for QUIC listener which "
635:           "doesn't work with connection balancer.");
636:     }
637:     udp_listener_config_->listener_factory_ = std::make_unique<Quic::ActiveQuicListenerFactory>(
638:         config.udp_listener_config().quic_options(), concurrency, quic_stat_names_,
639:         validation_visitor_, *listener_factory_context_);
640: #if UDP_GSO_BATCH_WRITER_COMPILETIME_SUPPORT
641:     // TODO(mattklein123): We should be able to use GSO without QUICHE/QUIC. Right now this causes
642:     // non-QUIC integration tests to fail, which I haven't investigated yet. Additionally, from
643:     // looking at the GSO code there are substantial copying inefficiency so I don't think it's
644:     // wise to enable to globally for now. I will circle back and fix both of the above with
645:     // a non-QUICHE GSO implementation.
646:     if (udp_listener_config_->writer_factory_ == nullptr &&
647:         Api::OsSysCallsSingleton::get().supportsUdpGso()) {
648:       udp_listener_config_->writer_factory_ = std::make_unique<Quic::UdpGsoBatchWriterFactory>();
649:     }
650: #endif
651: #else
652:     return absl::InvalidArgumentError("QUIC is configured but not enabled in the build.");
653: #endif
654:   } else {
655:     udp_listener_config_->listener_factory_ =
656:         std::make_unique<Server::ActiveRawUdpListenerFactory>(concurrency);
657:   }
658:   if (udp_listener_config_->writer_factory_ == nullptr) {
659:     udp_listener_config_->writer_factory_ = std::make_unique<Network::UdpDefaultWriterFactory>();
660:   }
661:   return absl::OkStatus();
662: }
