728: absl::Status
729: ListenerImpl::createListenerFilterFactories(const envoy::config::listener::v3::Listener& config) {
730:   if (!config.listener_filters().empty()) {
731:     switch (socket_type_) {
732:     case Network::Socket::Type::Datagram: {
733:       if (udp_listener_config_->listener_factory_->isTransportConnectionless()) {
734:         auto udp_listener_filter_factory_or_error =
735:             parent_.factory_->createUdpListenerFilterFactoryList(config.listener_filters(),
736:                                                                  *listener_factory_context_);
737:         RETURN_IF_NOT_OK_REF(udp_listener_filter_factory_or_error.status());
738:         udp_listener_filter_factories_ = std::move(*udp_listener_filter_factory_or_error);
739:       } else {
740:         absl::StatusOr<Filter::QuicListenerFilterFactoriesList>
741:             quic_listener_filter_factory_or_error =
742:                 parent_.factory_->createQuicListenerFilterFactoryList(config.listener_filters(),
743:                                                                       *listener_factory_context_);
744:         RETURN_IF_NOT_OK_REF(quic_listener_filter_factory_or_error.status());
745:         // This is a QUIC listener.
746:         quic_listener_filter_factories_ = std::move(*quic_listener_filter_factory_or_error);
747:       }
748:       break;
749:     }
750:     case Network::Socket::Type::Stream:
751:       auto listener_filter_factory_or_error = parent_.factory_->createListenerFilterFactoryList(
752:           config.listener_filters(), *listener_factory_context_);
753:       RETURN_IF_NOT_OK_REF(listener_filter_factory_or_error.status());
754:       listener_filter_factories_ = std::move(*listener_filter_factory_or_error);
755:       break;
756:     }
757:   }
758:   return absl::OkStatus();
759: }
