761: absl::Status
762: ListenerImpl::validateFilterChains(const envoy::config::listener::v3::Listener& config) {
763:   if (config.filter_chains().empty() && !config.has_default_filter_chain() &&
764:       (socket_type_ == Network::Socket::Type::Stream ||
765:        !udp_listener_config_->listener_factory_->isTransportConnectionless())) {
766:     // If we got here, this is a tcp listener or connection-oriented udp listener, so ensure there
767:     // is a filter chain specified
768:     return absl::InvalidArgumentError(
769:         fmt::format("error adding listener '{}': no filter chains specified",
770:                     absl::StrJoin(addresses_, ",", Network::AddressStrFormatter())));
771:   } else if (udp_listener_config_ != nullptr &&
772:              !udp_listener_config_->listener_factory_->isTransportConnectionless()) {
773:     // Early fail if any filter chain doesn't have transport socket configured.
774:     if (anyFilterChain(config, [](const auto& filter_chain) {
775:           return !filter_chain.has_transport_socket();
776:         })) {
777:       return absl::InvalidArgumentError(
778:           fmt::format("error adding listener '{}': no transport socket "
779:                       "specified for connection oriented UDP listener",
780:                       absl::StrJoin(addresses_, ",", Network::AddressStrFormatter())));
781:     }
782:   } else if ((!config.filter_chains().empty() || config.has_default_filter_chain()) &&
783:              udp_listener_config_ != nullptr &&
784:              udp_listener_config_->listener_factory_->isTransportConnectionless()) {
785: 
786:     return absl::InvalidArgumentError(
787:         fmt::format("error adding listener '{}': {} filter chain(s) specified for "
788:                     "connection-less UDP listener.",
789:                     absl::StrJoin(addresses_, ",", Network::AddressStrFormatter()),
790:                     config.filter_chains_size()));
791:   }
792:   return absl::OkStatus();
793: }
