805: absl::Status
806: ListenerImpl::buildConnectionBalancer(const envoy::config::listener::v3::Listener& config,
807:                                       const Network::Address::Instance& address) {
808:   auto iter = connection_balancers_.find(address.asString());
809:   if (iter == connection_balancers_.end() && socket_type_ == Network::Socket::Type::Stream) {
810: #ifdef WIN32
811:     // On Windows we use the exact connection balancer to dispatch connections
812:     // from worker 1 to all workers. This is a perf hit but it is the only way
813:     // to make all the workers do work.
814:     // TODO(davinci26): We can be faster here if we create a balancer implementation
815:     // that dispatches the connection to a random thread.
816:     ENVOY_LOG(warn,
817:               "ExactBalance was forced enabled for TCP listener '{}' because "
818:               "Envoy is running on Windows."
819:               "ExactBalance is used to load balance connections between workers on Windows.",
820:               config.name());
821:     connection_balancers_.emplace(address.asString(),
822:                                   std::make_shared<Network::ExactConnectionBalancerImpl>());
823: #else
824:     // Not in place listener update.
825:     if (config.has_connection_balance_config()) {
826:       switch (config.connection_balance_config().balance_type_case()) {
827:       case envoy::config::listener::v3::Listener_ConnectionBalanceConfig::kExactBalance:
828:         connection_balancers_.emplace(address.asString(),
829:                                       std::make_shared<Network::ExactConnectionBalancerImpl>());
830:         break;
831:       case envoy::config::listener::v3::Listener_ConnectionBalanceConfig::kExtendBalance: {
832:         const std::string connection_balance_library_type{TypeUtil::typeUrlToDescriptorFullName(
833:             config.connection_balance_config().extend_balance().typed_config().type_url())};
834:         auto factory =
835:             Envoy::Registry::FactoryRegistry<Network::ConnectionBalanceFactory>::getFactoryByType(
836:                 connection_balance_library_type);
837:         if (factory == nullptr) {
838:           return absl::InvalidArgumentError(
839:               fmt::format("Didn't find a registered implementation for type: '{}'",
840:                           connection_balance_library_type));
841:         }
842:         connection_balancers_.emplace(
843:             address.asString(),
844:             factory->createConnectionBalancerFromProto(
845:                 config.connection_balance_config().extend_balance(), *listener_factory_context_));
846:         break;
847:       }
848:       case envoy::config::listener::v3::Listener_ConnectionBalanceConfig::BALANCE_TYPE_NOT_SET: {
849:         return absl::InvalidArgumentError("No valid balance type for connection balance");
850:       }
851:       }
852:     } else {
853:       connection_balancers_.emplace(address.asString(),
854:                                     std::make_shared<Network::NopConnectionBalancerImpl>());
855:     }
856: #endif
857:   }
858:   return absl::OkStatus();
859: }
