872: void ListenerImpl::buildOriginalDstListenerFilter(
873:     const envoy::config::listener::v3::Listener& config) {
874:   // Add original dst listener filter if 'use_original_dst' flag is set.
875:   if (PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, use_original_dst, false)) {
876:     auto& factory =
877:         Config::Utility::getAndCheckFactoryByName<Configuration::NamedListenerFilterConfigFactory>(
878:             "envoy.filters.listener.original_dst");
879: 
880:     Network::ListenerFilterFactoryCb callback = factory.createListenerFilterFactoryFromProto(
