1023: bool ListenerImpl::supportUpdateFilterChain(const envoy::config::listener::v3::Listener& new_config,
1024:                                             bool worker_started) {
1025:   // The in place update needs the active listener in worker thread. worker_started guarantees the
1026:   // existence of that active listener.
1027:   if (!worker_started) {
1028:     return false;
1029:   }
1030: 
1031:   // Full listener update currently rejects tcp listener having 0 filter chain.
1032:   // In place filter chain update could survive under zero filter chain but we should keep the
1033:   // same behavior for now. This also guards the below filter chain access.
1034:   if (new_config.filter_chains_size() == 0) {
1035:     return false;
1036:   }
1037: 
1038:   // See buildProxyProtocolListenerFilter().
1039:   if (usesProxyProto(config()) ^ usesProxyProto(new_config)) {
1040:     return false;
1041:   }
1042: 
1043:   if (ListenerMessageUtil::filterChainOnlyChange(config(), new_config)) {
1044:     // We need to calculate the reuse port's default value then ensure whether it is changed or not.
1045:     // Since reuse port's default value isn't the YAML bool field default value. When
1046:     // `enable_reuse_port` is specified, `ListenerMessageUtil::filterChainOnlyChange` use the YAML
1047:     // default value to do the comparison.
1048:     return reuse_port_ == getReusePortOrDefault(parent_.server_, new_config, socket_type_);
1049:   }
1050: 
1051:   return false;
1052: }
