1068: void ListenerImpl::diffFilterChain(const ListenerImpl& another_listener,
1069:                                    std::function<void(Network::DrainableFilterChain&)> callback) {
1070:   for (const auto& message_and_filter_chain : filter_chain_manager_->filterChainsByMessage()) {
1071:     if (another_listener.filter_chain_manager_->filterChainsByMessage().find(
1072:             message_and_filter_chain.first) ==
1073:         another_listener.filter_chain_manager_->filterChainsByMessage().end()) {
1074:       // The filter chain exists in `this` listener but not in the listener passed in.
1075:       callback(*message_and_filter_chain.second);
1076:     }
1077:   }
1078:   // Filter chain manager maintains an optional default filter chain besides the filter chains
1079:   // indexed by message.
1080:   if (auto eq = MessageUtil();
1081:       filter_chain_manager_->defaultFilterChainMessage().has_value() &&
1082:       (!another_listener.filter_chain_manager_->defaultFilterChainMessage().has_value() ||
1083:        !eq(*another_listener.filter_chain_manager_->defaultFilterChainMessage(),
1084:            *filter_chain_manager_->defaultFilterChainMessage()))) {
1085:     callback(*filter_chain_manager_->defaultFilterChain());
1086:   }
1087: }
