1089: bool ListenerImpl::getReusePortOrDefault(Server::Instance& server,
1090:                                          const envoy::config::listener::v3::Listener& config,
1091:                                          Network::Socket::Type socket_type) {
1092:   bool initial_reuse_port_value = [&server, &config]() {
1093:     // If someone set the new field, adhere to it.
1094:     if (config.has_enable_reuse_port()) {
1095:       if (config.reuse_port()) {
1096:         ENVOY_LOG(warn,
1097:                   "both enable_reuse_port and reuse_port set on listener '{}', preferring "
1098:                   "enable_reuse_port.",
1099:                   config.name());
1100:       }
1101: 
1102:       return config.enable_reuse_port().value();
1103:     }
1104: 
1105:     // If someone set the old field to true, adhere to it.
1106:     if (config.reuse_port()) {
1107:       return true;
1108:     }
1109: 
1110:     // Otherwise use the server default which depends on hot restart.
1111:     return server.enableReusePortDefault();
1112:   }();
1113: 
1114: #ifndef __linux__
1115:   if (initial_reuse_port_value && socket_type == Network::Socket::Type::Stream) {
1116:     // reuse_port is the default on Linux for TCP. On other platforms even if set it is disabled
1117:     // and the user is warned. For UDP it's always the default even if not effective.
1118:     ENVOY_LOG(warn,
1119:               "reuse_port was configured for TCP listener '{}' and is being force disabled because "
1120:               "Envoy is not running on Linux. See the documentation for more information.",
1121:               config.name());
1122:     initial_reuse_port_value = false;
1123:   }
1124: #else
1125:   UNREFERENCED_PARAMETER(socket_type);
1126: #endif
1127: 
1128:   return initial_reuse_port_value;
1129: }
