1135: bool ListenerImpl::hasCompatibleAddress(const ListenerImpl& other) const {
1136:   if ((socket_type_ != other.socket_type_) || (addresses_.size() != other.addresses().size())) {
1137:     return false;
1138:   }
1139: 
1140:   // The listener support listening on the zero port address for test. Multiple zero
1141:   // port addresses are also supported. For comparing two listeners with multiple
1142:   // zero port addresses, only need to ensure there are the same number of zero
1143:   // port addresses. So create a copy of other's addresses here, remove it for any
1144:   // finding to avoid matching same zero port address to the same one.
1145:   auto other_addresses = other.addresses();
1146:   for (auto& addr : addresses()) {
1147:     auto iter = std::find_if(other_addresses.begin(), other_addresses.end(),
1148:                              [&addr](const Network::Address::InstanceConstSharedPtr& other_addr) {
1149:                                return *addr == *other_addr;
1150:                              });
1151:     if (iter == other_addresses.end()) {
1152:       return false;
1153:     }
1154:     other_addresses.erase(iter);
1155:   }
1156:   return true;
1157: }
