1159: bool ListenerImpl::hasDuplicatedAddress(const ListenerImpl& other) const {
1160:   // Skip the duplicate address check if this is the case of a listener update with new socket
1161:   // options.
1162:   if ((name_ == other.name_) &&
1163:       !ListenerMessageUtil::socketOptionsEqual(config(), other.config())) {
1164:     return false;
1165:   }
1166: 
1167:   if (socket_type_ != other.socket_type_) {
1168:     return false;
1169:   }
1170:   // For listeners that do not bind or listeners that do not bind to port 0 we must check to make
1171:   // sure we are not duplicating the address. This avoids ambiguity about which non-binding
1172:   // listener is used or even worse for the binding to port != 0 and reuse port case multiple
1173:   // different listeners receiving connections destined for the same port.
1174:   for (auto& other_addr : other.addresses()) {
1175:     if (other_addr->ip() == nullptr ||
1176:         (other_addr->ip() != nullptr && (other_addr->ip()->port() != 0 || !bindToPort()))) {
1177:       if (find_if(addresses_.begin(), addresses_.end(),
1178:                   [&other_addr](const Network::Address::InstanceConstSharedPtr& addr) {
1179:                     return *other_addr == *addr;
1180:                   }) != addresses_.end()) {
1181:         return true;
1182:       }
1183:     }
1184:   }
1185:   return false;
1186: }
