1202:                                              const envoy::config::listener::v3::Listener& rhs) {
1203:   if ((PROTOBUF_GET_WRAPPED_OR_DEFAULT(lhs, transparent, false) !=
1204:        PROTOBUF_GET_WRAPPED_OR_DEFAULT(rhs, transparent, false)) ||
1205:       (PROTOBUF_GET_WRAPPED_OR_DEFAULT(lhs, freebind, false) !=
1206:        PROTOBUF_GET_WRAPPED_OR_DEFAULT(rhs, freebind, false)) ||
1207:       (PROTOBUF_GET_WRAPPED_OR_DEFAULT(lhs, tcp_fast_open_queue_length, 0) !=
1208:        PROTOBUF_GET_WRAPPED_OR_DEFAULT(rhs, tcp_fast_open_queue_length, 0))) {
1209:     return false;
1210:   }
1211: 
1212:   bool is_equal =
1213:       std::equal(lhs.socket_options().begin(), lhs.socket_options().end(),
1214:                  rhs.socket_options().begin(), rhs.socket_options().end(),
1215:                  [](const ::envoy::config::core::v3::SocketOption& option,
1216:                     const ::envoy::config::core::v3::SocketOption& other_option) {
1217:                    return Protobuf::util::MessageDifferencer::Equals(option, other_option);
1218:                  });
1219:   if (!is_equal) {
1220:     return false;
1221:   }
1222: 
1223:   if (lhs.additional_addresses_size() != rhs.additional_addresses_size()) {
1224:     return false;
1225:   }
1226:   // Assume people won't change the order of additional addresses.
1227:   for (auto i = 0; i < lhs.additional_addresses_size(); i++) {
1228:     if (lhs.additional_addresses(i).has_socket_options() !=
1229:         rhs.additional_addresses(i).has_socket_options()) {
1230:       return false;
1231:     }
1232:     if (lhs.additional_addresses(i).has_socket_options()) {
1233:       is_equal =
1234:           std::equal(lhs.additional_addresses(i).socket_options().socket_options().begin(),
1235:                      lhs.additional_addresses(i).socket_options().socket_options().end(),
1236:                      rhs.additional_addresses(i).socket_options().socket_options().begin(),
1237:                      rhs.additional_addresses(i).socket_options().socket_options().end(),
