759: void ListenerOrchestrator::addListenerToWorker(Worker& worker,
760:                                               absl::optional<uint64_t> overridden_listener,
761:                                               ListenerImpl& listener,
762:                                               ListenerCompletionCallback completion_callback) {
763:   if (overridden_listener.has_value()) {
764:     ENVOY_LOG(debug, "replacing existing listener {}", overridden_listener.value());
765:   }
766:   worker.addListener(
767:       overridden_listener, listener,
768:       [this, completion_callback]() -> void {
769:         // The add listener completion runs on the worker thread. Post back to the main thread to
770:         // avoid locking.
771:         server_.dispatcher().post([this, completion_callback]() -> void {
772:           stats_.listener_create_success_.inc();
773:           if (completion_callback) {
774:             completion_callback();
775:           }
776:         });
777:       },
778:       server_.runtime(), server_.api().randomGenerator());
779: }
