1231: void ListenerOrchestrator::maybeCloseSocketsForListener(ListenerImpl& listener) {
1232:   if (!listener.udpListenerConfig().has_value() ||
1233:       listener.udpListenerConfig()->listenerFactory().isTransportConnectionless()) {
1234:     // Close the listen sockets right away to avoid leaving TCP connections in accept queue
1235:     // already waiting for long timeout. However, connection-oriented UDP listeners shouldn't
1236:     // close the socket because they need to receive packets for existing connections via the
1237:     // listen sockets.
1238:     listener.closeAllSockets();
1239: 
1240:     // In case of this listener was in-place updated previously and in the filter chains draining
1241:     // procedure, so close the sockets for the previous draining listener.
1242:     for (auto& manager : draining_filter_chains_manager_) {
1243:       // A listener can be in-place updated multiple times, so there may
1244:       // have multiple draining listeners with same tag.
1245:       if (manager.getDrainingListenerTag() == listener.listenerTag()) {
1246:         manager.getDrainingListener().closeAllSockets();
1247:       }
1248:     }
1249:   }
1250: }
