198:                   static_cast<const Protobuf::Message&>(proto_config.typed_config())));
199:     if (proto_config.config_type_case() ==
200:         envoy::config::listener::v3::ListenerFilter::ConfigTypeCase::kConfigDiscovery) {
201:       return absl::InvalidArgumentError(fmt::format("UDP listener filter: {} is configured with "
202:                                                     "unsupported dynamic configuration",
203:                                                     proto_config.name()));
204:       return ret;
205:     }
206:     // Now see if there is a factory that will accept the config.
207:     auto& factory =
208:         Config::Utility::getAndCheckFactory<Configuration::NamedUdpListenerFilterConfigFactory>(
209:             proto_config);
210: 
211:     auto message = Config::Utility::translateToFactoryConfig(
212:         proto_config, context.messageValidationVisitor(), factory);
213:     ret.push_back(factory.createFilterFactoryFromProto(*message, context));
214:   }
215:   return ret;
216: }
