218: absl::StatusOr<Filter::QuicListenerFilterFactoriesList>
219: ProdListenerComponentFactory::createQuicListenerFilterFactoryListImpl(
220:     const Protobuf::RepeatedPtrField<envoy::config::listener::v3::ListenerFilter>& filters,
221:     Configuration::ListenerFactoryContext& context,
222:     Filter::QuicListenerFilterConfigProviderManagerImpl& config_provider_manager) {
223:   Filter::QuicListenerFilterFactoriesList ret;
224: 
225:   ret.reserve(filters.size());
226:   for (ssize_t i = 0; i < filters.size(); i++) {
227:     const auto& proto_config = filters[i];
228:     ENVOY_LOG(debug, "  filter #{}:", i);
229:     ENVOY_LOG(debug, "    name: {}", proto_config.name());
230:     // dynamic listener filter configuration
231:     if (proto_config.config_type_case() ==
232:         envoy::config::listener::v3::ListenerFilter::ConfigTypeCase::kConfigDiscovery) {
233:       const envoy::config::core::v3::ExtensionConfigSource& config_discovery =
234:           proto_config.config_discovery();
235:       const std::string& name = proto_config.name();
236:       if (config_discovery.apply_default_config_without_warming() &&
237:           !config_discovery.has_default_config()) {
238:         return absl::InvalidArgumentError(fmt::format(
239:             "Error: listener filter config {} applied without warming but has no default config.",
240:             name));
241:       }
242:       for (absl::string_view type_url : config_discovery.type_urls()) {
243:         absl::string_view factory_type_url = TypeUtil::typeUrlToDescriptorFullName(type_url);
244:         if (Registry::FactoryRegistry<Server::Configuration::NamedQuicListenerFilterConfigFactory>::
245:                 getFactoryByType(factory_type_url) == nullptr) {
246:           return absl::InvalidArgumentError(fmt::format(
247:               "Error: no listener factory found for a required type URL {}.", factory_type_url));
248:         }
249:       }
250:       ret.push_back(config_provider_manager.createDynamicFilterConfigProvider(
251:           config_discovery, name, context.serverFactoryContext(), context,
252:           context.serverFactoryContext().clusterManager(), false, "quic-listener",
253:           createListenerFilterMatcher(proto_config)));
254:     } else {
255:       ENVOY_LOG(debug, "  config: {}",
256:                 MessageUtil::convertToStringForLogs(
257:                     static_cast<const Protobuf::Message&>(proto_config.typed_config())));
258:       // For static configuration, now see if there is a factory that will accept the config.
259:       auto& factory =
260:           Config::Utility::getAndCheckFactory<Configuration::NamedQuicListenerFilterConfigFactory>(
261:               proto_config);
262:       const auto message = Config::Utility::translateToFactoryConfig(
263:           proto_config, context.messageValidationVisitor(), factory);
264:       const auto callback = factory.createListenerFilterFactoryFromProto(
265:           *message, createListenerFilterMatcher(proto_config), context);
266:       ret.push_back(
267:           config_provider_manager.createStaticFilterConfigProvider(callback, proto_config.name()));
268:     }
269:   }
270:   return ret;
271: }
