1062: absl::StatusOr<Network::DrainableFilterChainSharedPtr>
1063: ListenerFilterChainFactoryBuilder::buildFilterChain(
1064:     const envoy::config::listener::v3::FilterChain& filter_chain,
1065:     FilterChainFactoryContextCreator& context_creator) const {
1066:   return buildFilterChainInternal(filter_chain,
1067:                                   context_creator.createFilterChainFactoryContext(&filter_chain));
