652: void ListenerOrchestrator::drainListener(ListenerImplPtr&& listener) {
653:   // First add the listener to the draining list.
654:   std::list<DrainingListener>::iterator draining_it = draining_listeners_.emplace(
655:       draining_listeners_.begin(), std::move(listener), workers_.size());
656: 
657:   // Using set() avoids a multiple modifiers problem during the multiple processes phase of hot
658:   // restart. Same below inside the lambda.
659:   stats_.total_listeners_draining_.set(draining_listeners_.size());
660: 
661:   // Tell all workers to stop accepting new connections on this listener.
662:   draining_it->listener_->debugLog("draining listener");
663:   const uint64_t listener_tag = draining_it->listener_->listenerTag();
664:   stopListener(*draining_it->listener_, {}, [this, listener_tag]() {
665:     for (auto& listener : draining_listeners_) {
666:       if (listener.listener_->listenerTag() == listener_tag) {
667:         maybeCloseSocketsForListener(*listener.listener_);
668:       }
669:     }
670:   });
671: 
672:   // Start the drain sequence which completes when the listener's drain manager has completed
673:   // draining at whatever the server configured drain times are.
674:   draining_it->listener_->localDrainManager().startDrainSequence([this, draining_it]() -> void {
675:     draining_it->listener_->debugLog("removing draining listener");
676:     for (const auto& worker : workers_) {
677:       // Once the drain time has completed via the drain manager's timer, we tell the workers
678:       // to remove the listener.
679:       worker->removeListener(*draining_it->listener_, [this, draining_it]() -> void {
680:         // The remove listener completion is called on the worker thread. We post back to the
681:         // main thread to avoid locking. This makes sure that we don't destroy the listener
682:         // while filters might still be using its context (stats, etc.).
683:         server_.dispatcher().post([this, draining_it]() -> void {
684:           if (--draining_it->workers_pending_removal_ == 0) {
685:             draining_it->listener_->debugLog("draining listener removal complete");
686:             draining_listeners_.erase(draining_it);
687:             stats_.total_listeners_draining_.set(draining_listeners_.size());
688:           }
689:         });
690:       });
691:     }
692:   });
693: 
694:   updateWarmingActiveGauges();
695: }
