739: bool ListenerOrchestrator::doFinalPreWorkerListenerInit(ListenerImpl& listener) {
740:   TRY_ASSERT_MAIN_THREAD {
741:     for (auto& socket_factory : listener.listenSocketFactories()) {
742:       absl::Status success = (socket_factory->doFinalPreWorkerInit());
743:       if (!success.ok()) {
744:         ENVOY_LOG(error, "final pre-worker listener init for listener '{}' failed: {}",
745:                   listener.name(), success.message());
746:         return false;
747:       }
748:     }
749:     return true;
750:   }
751:   END_TRY
752:   CATCH(EnvoyException & e, {
753:     ENVOY_LOG(error, "final pre-worker listener init for listener '{}' failed: {}", listener.name(),
754:               e.what());
755:     return false;
756:   });
757: }
